    "\n",
    "    n_recommendations = st.slider(\n",
    "        \"📋 Number of Recommendations\", 5, 20, 10\n",
    "    )\n",
    "\n",
    "    st.markdown(\"---\")\n",
    "    st.markdown(\"### 🧠 Algorithm Info\")\n",
    "    st.markdown(\"\"\"\n",
    "    <div style='font-size:0.85rem; color:#9090B0; line-height:1.8'>\n",
