    "    <div class='label'>📈 Avg Rating</div>\n",
    "  </div>\n",
    "  <div class='metric-card'>\n",
    "    <div class='value'>{sparsity:.0f}%</div>\n",
    "    <div class='label'>🕳️ Sparsity</div>\n",
